	line-height: 1.4;
	color: var(--wpf-muted);
}

.rst-wpf__track {
	display: flex;
	align-items: center;
	gap: 0;
	overflow-x: auto;
	padding: 2px 0;
	-webkit-overflow-scrolling: touch;
	scrollbar-width: thin;
}

.rst-wpf__step {
